function waitForElement(selector, timeout = 5000) {
    return new Promise((resolve, reject) => {
        const interval = 100;
        let elapsed = 0;
        const timer = setInterval(() => {
            const element = document.querySelector(selector);
            if (element) {
                clearInterval(timer);
                resolve(element);
            } else if (elapsed >= timeout) {
                clearInterval(timer);
                reject(new Error(`Élément ${selector} non trouvé après ${timeout} ms`));
            }
            elapsed += interval;
        }, interval);
    });
}

function getSelectedValue(selectId) {
    const el = document.getElementById(selectId);
    if (!el) return null;
    return el.options[el.selectedIndex]?.text || null;
}

function extractIngredients() {
    const ingredientNodes = document.querySelectorAll("#productList .ingredientTitle");
    const ingredients = Array.from(ingredientNodes).map(el => el.textContent.trim());

    const data = {
        ingredients: ingredients,
        categories: {
            category: getSelectedValue("advFilterCat"),
            subcategory: getSelectedValue("advFilterSubCat")
        },
        cuisines: {
            cuisine: getSelectedValue("advFilterCuisine")
        },
        seasonality: {
            month: getSelectedValue("advFilterSeasonality")
        },
        aromas: {
            aroma: getSelectedValue("advFilterFlavour")
        }
    };

    return data;
}

function waitAndClickLoadMore() {
    return new Promise((resolve) => {
        const button = document.querySelector("#loadMoreButton");
        if (!button || button.style.display === "none") {
            resolve(false);
            return;
        }

        button.click();
        setTimeout(() => {
            resolve(true);
        }, 1500); // laisse le temps au DOM de se mettre à jour
    });
}

async function getAllIngredientsWithPagination() {
    let previousCount = 0;
    let maxTries = 10;
    while (maxTries-- > 0) {
        const clicked = await waitAndClickLoadMore();
        const currentCount = document.querySelectorAll("#productList .ingredientTitle").length;
        if (!clicked || currentCount === previousCount) {
            break;
        }
        previousCount = currentCount;
    }
    return extractIngredients();
}

chrome.runtime.onMessage.addListener((request, sender, sendResponse) => {
    if (request.action === 'extract') {
        waitForElement("#productList", 7000)
            .then(() => getAllIngredientsWithPagination())
            .then(data => {
                sendResponse({ success: true, data });
            })
            .catch(err => {
                console.error("Erreur d’extraction :", err);
                sendResponse({ success: false, error: err.message });
            });
        return true; // permet d’attendre la réponse asynchrone
    }
});
